class Solution:
  def correct_anchor_tag(self, tag: str) -> str:
    href_regex = re.compile(r'href="([^"]*)"')
    if not href_regex.search(tag):
      tag = re.sub(r'href="[^"]*"', r'href="https://www.example.com"', tag)
    else:
      href = href_regex.search(tag).group(1)
      if not href.startswith("http://") and not href.startswith("https://"): 
        tag = re.sub(r'target="[^"]*"', r'target="_blank"', tag)
      else:
        tag = re.sub(r'target="[^"]*"', r'target="_blank"', tag)
    return tag

